import * as XLSX from 'xlsx';
import dayjs from 'dayjs';
import customParseFormat from 'dayjs/plugin/customParseFormat.js';

dayjs.extend(customParseFormat);

export const processCombinedData = (csvData, excelRaw) => {
  // 1. PROCESAR EXCEL (EASY DOCKING)
  const workbook = XLSX.read(excelRaw, { type: 'array' });
  const sheet = workbook.Sheets[workbook.SheetNames[0]];
  const rawMatrix = XLSX.utils.sheet_to_json(sheet, { header: 1 });

  const headers = rawMatrix[3]; // Fila 4 (Headers)
  const dataRows = rawMatrix.slice(4); // Datos

  const easyDockingClean = dataRows.map(row => {
    let obj = {};
    headers.forEach((h, i) => obj[h] = row[i]);
    return obj;
  }).filter(item => 
    item['TIPO DE OPERACIOn'] === "DESCARGA" && 
    item['ACCION'] === "add"
  );

  // 2. CONTEO DE ARRIBADOS (Easy Docking)
  const totalArribadosFisicos = easyDockingClean.reduce((acc, curr) => {
    const cant = parseFloat(curr['CANT PAQUETES']) || 0;
    return acc + cant;
  }, 0);

  // 3. CONTEO DE BIPEADOS (CSV Inbound)
  const totalBipeados = csvData.filter(d => 
    d['Labeling Date Printed'] && d['Labeling Date Printed'].trim() !== ""
  ).length;

  // 4. CÁLCULO DE PENDIENTES
  const piezasPendientes = totalArribadosFisicos - totalBipeados;

  // 5. CONFIGURAR FRANJAS HORARIAS (05:00 a 23:00)
  const franjas = [];
  for (let i = 5; i <= 23; i++) {
    franjas.push(`${i.toString().padStart(2, '0')}:00`);
  }

  const chartMap = {};
  franjas.forEach(h => chartMap[h] = { hora: h, arribo: 0, bipeo: 0 });

  // 6. PROCESAR ARRIBOS PARA GRÁFICA (Excel)
  easyDockingClean.forEach(row => {
    if (row['Fecha y hor']) {
      const hora = dayjs(row['Fecha y hor']).format('HH:00');
      if (chartMap[hora]) {
        chartMap[hora].arribo += (parseFloat(row['CANT PAQUETES']) || 0);
      }
    }
  });

  // 7. PROCESAR BIPEOS PARA GRÁFICA (CSV)
  csvData.forEach(row => {
    const rawDate = row['Labeling Date Printed'];
    if (rawDate) {
      const hora = dayjs(rawDate, "DD/MM/YYYY HH:mm:ss").format('HH:00');
      if (chartMap[hora]) chartMap[hora].bipeo++;
    }
  });

  // 8. TABLA DE ARMADO DE HU
  const tableData = franjas.map(hora => {
    const enIntervalo = csvData.filter(d => 
      d['Labeling Date Printed'] && 
      dayjs(d['Labeling Date Printed'], "DD/MM/YYYY HH:mm:ss").format('HH:00') === hora
    );

    return {
      intervalo: `${hora} - ${dayjs('2026-01-01 ' + hora).add(1, 'hour').format('HH:00')}`,
      etiquetado: Math.max(enIntervalo.length + 200, 1000), // Meta simulada
      piezas: enIntervalo.length,
      usuarios: [...new Set(enIntervalo.map(d => d['Inbound User ID']))].length || 0
    };
  });

  return {
    kpis: {
      total: totalBipeados.toLocaleString(), // Ahora muestra los bipeados reales
      pendientes: piezasPendientes > 0 ? piezasPendientes.toLocaleString() : "0", // Resta Arribos - Bipeos
      eficiencia: totalArribadosFisicos > 0 ? ((totalBipeados / totalArribadosFisicos) * 100).toFixed(2) : "0.00"
    },
    chartData: Object.values(chartMap),
    tableData: tableData,
    matrix: {
      chasis: easyDockingClean.filter(d => d['TRANSPORTE'] === 'Chasis').length,
      camioneta: easyDockingClean.filter(d => d['TRANSPORTE']?.includes('Camioneta')).length,
      semi: easyDockingClean.filter(d => d['TRANSPORTE'] === 'Semi').length
    }
  };
};
